def dump():
    full = {}
    if os.path.exists(BASE):
        full = json.load(open(BASE, encoding="utf-8"))
    for k, v in NEW.items():
        full[str(k)] = v
    json.dump(full, open(BASE, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
    print(f"merged NEW: {len(NEW)}  |  {BASE} keys total: {len(full)}")

if __name__ == "__main__":
    dump()
